import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class BankingService {
    public void processTransaction(Connection connection, int accountId, double transactionAmount) throws SQLException {
        connection.setAutoCommit(false);
        try (PreparedStatement selectStmt = connection.prepareStatement(
                "SELECT balance FROM accounts WHERE account_id = ? FOR UPDATE");
             PreparedStatement updateStmt = connection.prepareStatement(
                "UPDATE accounts SET balance = ? WHERE account_id = ?")) {
            
            selectStmt.setInt(1, accountId);
            double currentBalance = 0.0;
            
            try (ResultSet rs = selectStmt.executeQuery()) {
                if (rs.next()) {
                    currentBalance = rs.getDouble("balance");
                } else {
                    throw new SQLException("Account not found");
                }
            }
            
            if (currentBalance + transactionAmount < 0) {
                throw new SQLException("Insufficient funds");
            }

            double newBalance = currentBalance + transactionAmount;
            updateStmt.setDouble(1, newBalance);
            updateStmt.setInt(2, accountId);
            updateStmt.executeUpdate();

            connection.commit();
        } catch (SQLException e) {
            connection.rollback();
            throw e;
        } finally {
            connection.setAutoCommit(true);
        }
    }
}